80	int yolo3_detection_output_init_params()
81	{
82	    num_class = 80;      // 对应yolo层classes
83	    num_box = 3;         // 单个yolo层里mask数值的个数
84	    confidence_threshold = 0.25;
85	    nms_threshold = 0.5;   // 对应yolo层的nms_thresh， 没有的话设置为0.45
86	
87	    biases.clear();
88	    mask.clear();
89	    anchors_scale.clear();
90	
91	    // 10,14,  23,27,  37,58,  81,82,  135,169,  344,319
92	    biases.push_back(10.000000);     // 对应yolo层的anchors，每个yolo层该参数都一样
93	    biases.push_back(14.000000);
94	    biases.push_back(23.000000);
95	    biases.push_back(27.000000);
96	    biases.push_back(37.000000);
97	    biases.push_back(58.000000);
98	    biases.push_back(81.000000);
99	    biases.push_back(82.000000);
100	    biases.push_back(135.000000);
101	    biases.push_back(169.000000);
102	    biases.push_back(344.000000);
103	    biases.push_back(319.000000);
104	
105	    mask.push_back(3.000000);   // 对应yolo层mask。每个yolo层不一样。要按yolo层顺序来添加
106	    mask.push_back(4.000000);
107	    mask.push_back(5.000000);
108	    mask.push_back(1.000000);
109	    mask.push_back(2.000000);
110	    mask.push_back(3.000000);
111	
112	    // 几个yolo层，就有几个anchors_scale
113	    // 计算方式： input_w * scale_x_y / yolo_w
114	    // input_w为输入维度416
115	    // scale_x_y为yolo层里的参数1.05
116	    // yolo_w为yolo层的输入维度。可以用可视化软件Netron查看yolo层输入，每个yolo层输入维度不一样。
117	    // 这里yolo4tiny的yolo层输入为13和26
118	    // 416*1.05/13=33.6
119	    // 416*1.05/26=16.8
120	    anchors_scale.push_back(33.600000);
121	    anchors_scale.push_back(16.800000);
