126	struct BBoxRect
127	{
128	    float xmin;
129	    float ymin;
130	    float xmax;
131	    float ymax;
132	    int label;
133	};
134	
135	static inline float intersection_area(const BBoxRect& a, const BBoxRect& b)
136	{
137	    if (a.xmin > b.xmax || a.xmax < b.xmin || a.ymin > b.ymax || a.ymax < b.ymin)
138	    {
139	        // no intersection
140	        return 0.f;
141	    }
142	
143	    float inter_width = std::min(a.xmax, b.xmax) - std::max(a.xmin, b.xmin);
144	    float inter_height = std::min(a.ymax, b.ymax) - std::max(a.ymin, b.ymin);
145	
146	    return inter_width * inter_height;
147	}
