149	template <typename T>
150	static void qsort_descent_inplace(std::vector<T>& datas, std::vector<float>& scores, int left, int right)
151	{
152	    int i = left;
153	    int j = right;
154	    float p = scores[(left + right) / 2];
155	
156	    while (i <= j)
157	    {
158	        while (scores[i] > p)
159	            i++;
160	
161	        while (scores[j] < p)
162	            j--;
163	
164	        if (i <= j)
165	        {
166	            // swap
167	            std::swap(datas[i], datas[j]);
168	            std::swap(scores[i], scores[j]);
169	
170	            i++;
171	            j--;
172	        }
173	    }
174	
175	    if (left < j)
176	        qsort_descent_inplace(datas, scores, left, j);
177	
178	    if (i < right)
179	        qsort_descent_inplace(datas, scores, i, right);
180	}
181	
182	template <typename T>
183	static void qsort_descent_inplace(std::vector<T>& datas, std::vector<float>& scores)
184	{
185	    if (datas.empty() || scores.empty())
186	        return;
187	
188	    qsort_descent_inplace(datas, scores, 0, scores.size() - 1);
189	}
