112		// resize image.
113		unsigned char* inbuf_resized = (unsigned char*)0x39000000; //(unsigned char*)malloc(net_in_w*net_in_h*net_in_c);
114		if (inbuf_resized == NULL) return eeperr_Malloc;
115		if (net_in_c == 3)
116		{
117			resize_bilinear_c3(inputbuf, img_w, img_h, inbuf_resized, net_in_w, net_in_h);
